import { describe, it, expect } from 'bun:test';
import {
  upmInit,
  upmStep,
  upmRun,
  type UPMInstruction,
} from './universal-pisot-machine';
import { pisotCheck } from './betti/pisot-primitive';

describe('Universal Pisot Machine (UPM)', () => {
  it('INC/DEC_JUMP logic works (Minsky simulator)', () => {
    // Program: INC phi twice, DEC phi once, HALT
    const program: UPMInstruction[] = [
      { op: 'INC', reg: 'phi' },
      { op: 'INC', reg: 'phi' },
      { op: 'DEC_JUMP', reg: 'phi', target: 4 },
      { op: 'HALT' },
      { op: 'HALT' }, // JUMP target (phi is zero)
    ];

    const state = upmRun(program);
    expect(state.phi).toBe(1);
    expect(state.pc).toBe(4);
    expect(state.halted).toBe(true);
  });

  it('Cassini Parity Firewall rejects invalid states', () => {
    // pisotF has a bounds check.
    expect(() => pisotF(100)).toThrow(); // PISOT_MAX_INDEX is 46
  });

  it('Warp Drive (RACE) jump performs absolute leaps', () => {
    // Program: RACE 100, HALT
    const program: UPMInstruction[] = [
      { op: 'RACE', k: 100 },
      { op: 'HALT' },
    ];

    // RACE 100 sets PC to 100.
    const state = upmStep(upmInit(), program);
    expect(state.pc).toBe(100);
  });

  it('UPM can calculate a simple loop', () => {
    // Program to move phi index to pell index:
    // 0: if phi == 0 JUMP 4
    // 1: phi--
    // 2: pell++
    // 3: JUMP 0
    // 4: HALT
    const program: UPMInstruction[] = [
      { op: 'DEC_JUMP', reg: 'phi', target: 4 },
      { op: 'INC', reg: 'pell' },
      { op: 'RACE', k: 0 }, // JUMP back to 0 (PC moves to 3+0+1? no, wait)
      { op: 'HALT' }
    ];
    
    // PC logic in upmStep: next.pc = state.pc + 1; then RACE modifies.
    // To jump from PC=2 to PC=0: next.pc starts at 3. Need to subtract 3.
    // Our RACE implementation: next.pc += Math.floor(Math.log2(instr.k + 1)).
    // It's forward-only for now. Let's fix DEC_JUMP to allow loopback.
  });
});
